d:"Remember your old password?",enterOtpTitle:"Enter Your OTP",sentCodeToEmailDesc:"We sent a 6-digit confirmation code to",verifyOtpHeader:"Verify OTP",verifyIdentityDesc:"Verify your identity to reset password.",sixDigitCodeLabel:"6-Digit Code",verifyCodeBtn:"Verify Code",verifying:"Verifying...",didntReceive:"Didn't receive it?",availableTravelers:"Available Travelers",findTravelersDesc:"Find travelers to deliver your package",selectCity:"Select city",findRoutesBtn:"Find Routes",filters:"Filters",travelDate:"Travel Date",allModes:"All modes",weightKg:"Weight (kg)",applyFilters:"Apply Filters",noTripsFound:"No trips found",tryAdjusting:"Try adjusting your search criteria or check back later.",postYourTrip:"Post Your Trip",spaceAvailable:"available",rateStandard:"Standard",sendRequestBtn:"Send Request",inTransit:"In Transit",outForDelivery:"Out for Delivery",completed:"Completed",heroTitleOrig:"Global Package Delivery.",heroSubtitle:"Send packages",heroWith:"with courier partners.",leavingFrom:"Departure Country or City",goingTo:"Arrival Country or City",today:"Date",passengers:"Courier Partners",search:"Search",showStays:"Show stays",promoTitle:"Earn from your travels.",promoDesc:"Help others send packages as a delivery partner. Post your route and get paid for your available luggage space.",shareRide:"Post a trip",featureTitle1:"Send everywhere",featureDesc1:"Send packages safely to any city. Our delivery partners go everywhere you need.",featureTitle2:"Earn from luggage space",featureDesc2:"Turn your extra luggage space into cash. A simple way to subsidize your travel costs.",featureTitle3:"Trust built-in",featureDesc3:"We verify every delivery partner and sender. Your package is in safe hands, every step of the way.",busDesc:"Affordable way to send domestic packages",ratingsTitle:"Automatic Ratings.",ratingsSubtitle:"More reliable",ratingsSubtitle2:"service.",ratingsDesc:"We are launching Automatic Ratings to make profiles fairer and more accurate. This keeps profiles accurate so you can send with more confidence!",getGoing:"Get going",aboutHero:"Revolutionizing Logistics for Everyone.",aboutSubtitle:"Bago connects travelers with people who need to send packages across the world. We're building a more connected, efficient, and human way to ship.",ourStory:"Our Story",storyTitle:"Born from a simple travel observation.",storyDesc1:"The idea for Bago started when we noticed how much empty luggage space goes to waste every day across thousands of flights and bus routes. Meanwhile, sending a small parcel internationally remains prohibitively expensive and slow.",storyDesc2:"We realized that travelers are the ultimate delivery network. By connecting these two groups, Bago creates a win-win: senders get faster, cheaper delivery, and travelers earn extra income to subsidize their journeys.",coreValues:"Our Core Values",trustSafety:"Trust & Safety",trustDesc:"Every member is verified. We prioritize the security of your items and your personal data above all else.",globalCommunity:"Global Community",globalDesc:"We are building a borderless world where people help people, regardless of geography or distance.",innovation:"Innovation",innovationDesc:"Using technology to solve old problems in new ways. Constant improvement is in our DNA.",overview:"Overview",myTrips:"My Trips",myShipments:"My Shipments",chats:"Chats",earnings:"Earnings",settings:"Settings",verification:"Verification",verifiedMember:"Verified Member",unverifiedMember:"Unverified Member",identityConfirmed:"Identity fully confirmed.",underReview:"Under Review",reviewDocs:"Hang tight! Reviewing docs.",verifyNow:"Verify Now",postTripSubtitle:"Share your journey and earn by delivering packages",route:"Route",fromCountry:"From — Country",fromCity:"From — City",toCountry:"To — Country",toCity:"To — City",travelDates:"Travel Dates",departureDate:"Departure Date",arrivalDate:"Arrival Date",transportModeLabel:"Transport Mode",capacity:"Capacity",maxWeight:"Maximum 50 kg per trip"